import java.util.Arrays;

public class Solution {

    // DSU structure variables
    private int[] parent;
    // dist[i]: parity of the weight of the path from node i to its current parent[i]
    private int[] dist; 

    /**
     * Finds the root of node i and updates dist[i] to represent the parity of the path 
     * from i to the root.
     * @param i The node index.
     * @return The root of the set containing i.
     */
    private int find(int i) {
        if (parent[i] == i) {
            return i;
        }

        // Recursively find the root
        int root = find(parent[i]);

        // Path compression: Update dist[i]
        // New distance (i -> root) = (i -> old_parent) XOR (old_parent -> root)
        dist[i] = dist[i] ^ dist[parent[i]];

        parent[i] = root;
        return root;
    }

    public static long solve(long n, long[][] edges) {
        Solution solver = new Solution();
        int N = (int) n;

        solver.parent = new int[N];
        solver.dist = new int[N];

        // Initialization
        for (int i = 0; i < N; i++) {
            solver.parent[i] = i;
            solver.dist[i] = 0; // Distance from i to itself is 0
        }

        long acceptedEdgesCount = 0;

        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            int w = (int) edge[2]; // w is 0 or 1

            int rootU = solver.find(u);
            int rootV = solver.find(v);

            // dU is the parity of the path u -> rootU
            int dU = solver.dist[u]; 
            // dV is the parity of the path v -> rootV
            int dV = solver.dist[v]; 

            if (rootU == rootV) {
                // Case 1: u and v are already in the same component. Adding this edge closes a cycle.

                // Parity of the existing path u -> v is dU ^ dV.
                // The new cycle parity is (dU ^ dV) ^ w.

                if ((dU ^ dV ^ w) == 0) {
                    // Cycle weight is even. Accept the edge.
                    acceptedEdgesCount++;
                } 
                // else: Cycle weight is odd. Reject the edge.

            } else {
                // Case 2: u and v are in different components. Merge the sets.

                // We merge rootV into rootU.
                solver.parent[rootV] = rootU;

                // We need to calculate the new distance dist[rootV] = Parity(rootV -> rootU).
                // Path: rootV -> v (parity dV) -> u (parity w) -> rootU (parity dU).
                // Note: Weight(a -> b) = Weight(b -> a) mod 2.
                // Weight(rootV -> v) = dV.

                // Parity(rootV -> rootU) = Parity(rootV -> v) ^ Parity(v -> u) ^ Parity(u -> rootU)
                // Parity(v -> u) = w.

                solver.dist[rootV] = dV ^ w ^ dU;

                // Accept the edge as it maintains the even cycle property globally.
                acceptedEdgesCount++;
            }
        }

        return acceptedEdgesCount;
    }
}

