class Solution {
    static class DSU {
        int[] P;
        // D[i]: parity of the path weight from node i to its direct parent P[i]
        int[] D; 
        int N;

        DSU(int n) {
            this.N = n;
            P = new int[n];
            D = new int[n];
            for (int i = 0; i < n; i++) {
                P[i] = i;
                D[i] = 0;
            }
        }

        // Returns the root R. Updates D[i] to be the parity of path i -> R (path compression).
        int find(int i) {
            if (P[i] == i) {
                return i;
            }

            // Recursively find root R
            int root = find(P[i]);

            // Update distance: new D[i] = old D[i] + D[P[i]] (since D[P[i]] now stores parity P[i] -> root)
            D[i] = (D[i] + D[P[i]]) % 2;

            P[i] = root;
            return root;
        }

        // Attempts to union u and v with weight w.
        // Returns true if the edge is added (i.e., it maintains the even cycle property).
        boolean union(int u, int v, int w) {
            int rootU = find(u);
            int rootV = find(v);

            // d_u is parity u -> rootU
            int d_u = D[u];
            // d_v is parity v -> rootV
            int d_v = D[v];

            if (rootU == rootV) {
                // Same component. Check cycle consistency.
                // An existing path P between u and v has parity d_u ^ d_v.
                // For the new cycle (P + w) to be even, w must equal d_u ^ d_v.
                return (d_u ^ d_v) == w;
            } else {
                // Different components. Merge them (e.g., rootU attaches to rootV).
                P[rootU] = rootV;

                // Calculate D[rootU]: parity of path rootU -> rootV
                // Path sequence: rootU -> u -> v -> rootV
                // Parity = (rootU -> u) + (u -> v) + (v -> rootV) mod 2
                // Note: rootU -> u has parity d_u (since d_u = u -> rootU, and weights are symmetric)
                // D[rootU] = d_u ^ w ^ d_v
                D[rootU] = (d_u + w + d_v) % 2;

                return true; // Always valid when merging components
            }
        }
    }

    public static long solve(long n, long[][] edges) {
        int N = (int) n;
        DSU dsu = new DSU(N);
        long addedEdgesCount = 0;

        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            int w = (int) edge[2];

