import java.util.Arrays;

public class Solution {

    private static int[] parent;
    // dist[i] stores the parity of the path weight from node i to its current parent.
    private static int[] dist;

    /**
     * Finds the root of node i and updates the distance array using path compression.
     * Returns a pair {root, parity_i_to_root}.
     */
    private static int[] find(int i) {
        if (parent[i] == i) {
            return new int[]{i, 0}; // Root found, distance to itself is 0 (even).
        }

        // Recursive call to find root and distance of parent
        int[] rootInfo = find(parent[i]);
        int root = rootInfo[0];
        int parityParentToRoot = rootInfo[1];

        // Path compression: set i's parent directly to the root
        parent[i] = root;

        // Update distance[i]: New distance from i to root is (i -> parent[i] -> root)
        // dist[i] is i -> old_parent[i]
        // parityParentToRoot is old_parent[i] -> root
        dist[i] = (dist[i] + parityParentToRoot) % 2;

        return new int[]{root, dist[i]};
    }

    public static long solve(long n, long[][] edges) {
        int N = (int) n;
        parent = new int[N];
        dist = new int[N];

        // Initialize DSU
        for (int i = 0; i < N; i++) {
            parent[i] = i;
            dist[i] = 0;
        }

        int edgesAddedCount = 0;

        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            int w = (int) edge[2]; // w is 0 or 1

            // 1. Find roots and relative parities
            int[] infoU = find(u);
            int rootU = infoU[0];
            int parityU = infoU[1]; // Parity of path u -> rootU

            int[] infoV = find(v);
            int rootV = infoV[0];
            int parityV = infoV[1]; // Parity of path v -> rootV

            if (rootU == rootV) {
                // Case 1: Same component. Check cycle consistency.
                // Path u -> v within component has parity: parityU + parityV (mod 2)
                // Cycle parity = (u->v path) + w
                int cycleParity = (parityU + parityV + w) % 2;

                if (cycleParity == 0) {
                    // Even cycle sum, consistent. Add edge.
                    edgesAddedCount++;
                } else {
                    // Odd cycle sum, violates condition. Discard edge.
                }
            } else {
                // Case 2: Different components. Merge components. Edge is always valid.
                edgesAddedCount++;

                // Union by rank/size optimization is usually done, but simple union suffices here.
                // Merge rootV into rootU. Set parent[rootV] = rootU.
                parent[rootV] = rootU;

                // Calculate the new distance dist[rootV]: parity of path rootV -> rootU
                // Path: rootV -> v (parityV) -> u (w) -> rootU (parityU)
                // Note: Weights are undirected. W(a->b) = W(b->a).
                // W(rootV -> v) = parityV
                // W(v -> u) = w
                // W(u -> rootU) = parityU

                // Parity of path rootV -> rootU:
                int newDistRootVToRootU = (parityV + w + parityU) % 2;
                dist[rootV] = newDistRootVToRootU;
            }
        }

        return edgesAddedCount;
    }
}

